SELECT 
    /* @SQLID=SUB0202_0403-02_1#Sql001 */  
    COUNT(1) as row_count
FROM 
    ETRADE.FUND_RESERVE_ORDER@CORDYS_ET10.WORLD A
WHERE
    A.BUTEN_CODE = #{req.butenCode}
    AND TO_NUMBER(TRIM(A.ACCOUNT_NUMBER)) = #{req.accountNumber}
    AND A.NRI_CODE_KAISU = #{req.mfkaisu}
    AND A.NRI_CODE_GO = #{req.mfgo}
    AND A.DELETE_KBN='0'

SELECT 
    /* @SQLID=SUB0202_0403-02_1#Sql001 */  
    COUNT(1) as row_count
FROM 
    ETRADE.CREDIT_RESERVE_ORDER@CORDYS_ET10.WORLD A
WHERE
    A.BUTEN_CODE = #{req.butenCode}
    AND TO_NUMBER(TRIM(A.ACCOUNT_NUMBER)) = #{req.accountNumber}
    AND A.NRI_CODE_KAISU = #{req.mfkaisu}
    AND A.NRI_CODE_GO = #{req.mfgo}
    AND A.DELETE_KBN='0'
